import { LightningElement, api, wire } from 'lwc';
import getAccountDetails from '@salesforce/apex/GetAccounts.getAccountDetails';
import getContactSegmentStatus from '@salesforce/apex/GetCustomersFromSegment.getContactSegmentStatus';

export default class PersonAccountCard extends LightningElement {
    @api recordId;
    message = 'Get Customers with Recalled Products';
    accountId = '';
    message = '';

    @wire(getAccountDetails, { accountId: '$recordId' })
    account;

    @wire(getContactSegmentStatus, { id: '$recordId' })
    wiredSegment({ data, error }) {
        console.log('Record Id is:',this.recordId);
        if (data) {
            console.log('Data received from Apex:', data);
            this.message = data;
        }else if(data == null || data == ''){
            console.log('Data received from Apex:', data);
            this.message = '';
        } else if (error) {
            console.error('Error:', error);
        }
    }

    get hasData() {
        console.log('## this.account = '+this.account);
        return this.account?.data !== undefined;
    }
    
    get error() {
            return this.account?.error;
        }

    get personContactId(){
        return this.account?.data?.PersonContactId;
       }

    get name() {
            return this.account?.data?.Name;
        }
    
    get billingCity() {
            return this.account?.data?.BillingCity;
        }
    
    get billingState() {
            return this.account?.data?.BillingState;
        }
    
    get billingPostalCode() {
            return this.account?.data?.BillingPostalCode;
        }
    
    get billingStreet() {
            return this.account?.data?.BillingStreet;
        }

    get lifetimeValue() {
            const value = this.account?.data?.Contacts?.[0]?.Lifetime_Value__c;
            return (value || value === 0) ? (Math.round(value * 100) / 100) : '';
        }

    get averagePurchaseValue() {
            const value = this.account?.data?.Contacts?.[0]?.Average_Purchase_Value__c;
            return (value || value === 0) ? (Math.round(value * 100) / 100) : '';
        }

    get photoURL() {
        return 'data:image/png;base64,';
    } 

    get Customer_StorePreference() {
        return this.account?.data?.Contacts?.[0]?.Customer_StorePreference__c;
    }

    get Customer_FamilySizes() {
        return this.account?.data?.Contacts?.[0]?.Customer_FamilySizes__c;
    }

    get Customer_ProjectFrequency() {
        return this.account?.data?.Contacts?.[0]?.Customer_ProjectFrequency__c;
    }

    get Customer_GarageSize() {
        return this.account?.data?.Contacts?.[0]?.Customer_GarageSize__c;
    }

    get Customer_OwnershipStatus() {
        return this.account?.data?.Contacts?.[0]?.Customer_OwnershipStatus__c;
    }

    get Customer_PurchaseFrequency() {
        return this.account?.data?.Contacts?.[0]?.Customer_PurchaseFrequency__c;
    }

    get Customer_SkillLevel() {
        return this.account?.data?.Contacts?.[0]?.Customer_SkillLevel__c;
    }

    get Customer_ResidenceType() {
        return this.account?.data?.Contacts?.[0]?.Customer_ResidenceType__c;
    }

    get Customer_Seasonality() {
        return this.account?.data?.Contacts?.[0]?.Customer_Seasonality__c;
    }

}